mapper.sql:
AND EXISTS (
    SELECT 1
    FROM VW_USER_PROJECT_AUTH vupa
    WHERE vupa.user_code = #{userCode}
      AND vupa.project_code = ${alias}.project_code
      AND vupa.category = #{category}
      AND (
            #{admin} = 1
         OR vupa.rd_rol = 'Y'

            AND vupa.del_rol = 'Y'

      )
)

EXISTS (
    SELECT 1
    FROM VW_USER_AUTH vua
    LEFT JOIN VW_USER_PROJECT_AUTH vupa
           ON vupa.user_code = vua.user_code
          AND vupa.project_code = #{projectCode}
          AND vupa.category = #{category}
    WHERE vua.user_code = #{userCode}
      AND (
            vua.admin_ck = 'Y'
         OR (
              vupa.rd_rol = 'Y'

              AND NVL(vupa.${roleColumn}, 'N') = 'Y'

            )
      )
)
